// Simulamos que tenemos un access_token válido (en prod, vendría de Google OAuth2)
const accessToken = process.env.GOOGLE_ACCESS_TOKEN || 'test_token_for_demo';

const emailBody = `
Hola Brand_0145,

Espero te encuentres bien. Vimos que tienes un GMV interesante en BNPL (COP 4,908 MM anuales).

Addi Marketplace te ofrece acceso a más de 10 millones de usuarios potenciales y comisiones competitivas.

¿Te gustaría agendar una llamada de 15 minutos? Aquí está el calendario: [enlace]

Saludos,
Equipo GTM de Addi
`;

const to = '${DEMO_EMAIL_DESTINO}';
const from = 'gtm@addi.com';
const subject = 'Expansión de catálogo en Addi Marketplace';

// Construir email en formato RFC 2822
const emailStr = `From: ${from}\nTo: ${to}\nSubject: ${subject}\nContent-Type: text/plain; charset=utf-8\n\n${emailBody}`;

// Convertir a base64
const base64Email = Buffer.from(emailStr).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');

return {
  accessToken: accessToken,
  base64Email: base64Email,
  emailRaw: emailStr,
  to: to
};

// Capturar respuesta o error
return {
  status: 'sent_or_error',
  responseStatus: $json.status || 'unknown',
  messageId: $json.id || 'no_id',
  errorCode: $json.error ? $json.error.code : null,
  errorMessage: $json.error ? $json.error.message : 'Success or pending auth',
  timestamp: new Date().toISOString()
};
